- Rep: {{ $('Recording Webhook').item.json.body.rep_email }}

parameters.jsCode:
// Parse OpenAI JSON response and build HubSpot note body
const analysis = JSON.parse($json.message.content);
const callMeta = $('Recording Webhook').item.json.body;

const scoreEmoji = analysis.call_quality_score >= 8 ? '🟢' : analysis.call_quality_score >= 6 ? '🟡' : '🔴';

const noteBody = `SALES CALL ANALYSIS\n${'='.repeat(50)}\n\n` +
  `Score: ${scoreEmoji} ${analysis.call_quality_score}/10\n` +
  `Overall Sentiment: ${analysis.overall_sentiment}\n` +
  `Prospect Engagement: ${analysis.prospect_engagement_level}\n` +
  `Rep Talk Ratio: ${analysis.rep_talk_ratio_pct}%\n\n` +
  `EXECUTIVE SUMMARY\n${analysis.executive_summary}\n\n` +
  `BUYING SIGNALS\n${analysis.buying_signals.map(s => `• ${s}`).join('\n')}\n\n` +
  `OBJECTIONS RAISED\n${analysis.objections_raised.map(o => `• ${o}`).join('\n')}\n\n` +
  `NEXT STEPS AGREED\n${analysis.next_steps_agreed.map(s => `• ${s}`).join('\n')}\n\n` +
  `RECOMMENDED ACTION\n${analysis.recommended_action}\n\n` +
  `COACHING NOTES\n${analysis.coaching_points.map(c => `• ${c}`).join('\n')}`;

return {
  json: {
    deal_id: callMeta.deal_id,
    rep_email: callMeta.rep_email,
    rep_slack_id: callMeta.rep_slack_id || null,
    note_body: noteBody,
    analysis,
    score_emoji: scoreEmoji,
    call_duration: callMeta.call_duration_mins
  }
};

